package com.doc.entity.vendor;

import jakarta.persistence.*;
import lombok.*;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;

/**
 * VendorQuotation represents quotation submitted by a vendor against one RFQ.
 *
 * Example:
 * RFQ-CDSO-0622 was sent to Balaji Traders.
 * Balaji submitted quotation of Rs. 8,50,000.
 */
@Entity
@Table(
        name = "vendor_quotations",
        uniqueConstraints = {
                @UniqueConstraint(
                        name = "uk_rfq_vendor_quotation_version",
                        columnNames = {"rfq_vendor_id", "version_no"}
                )
        },
        indexes = {
                @Index(name = "idx_quotation_number", columnList = "quotationNumber", unique = true),
                @Index(name = "idx_quotation_status", columnList = "status"),
                @Index(name = "idx_quotation_rfq", columnList = "rfq_id"),
                @Index(name = "idx_quotation_vendor", columnList = "vendor_id")
        }
)
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
public class  VendorQuotation {

    /**
     * Primary key of vendor quotation table.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /**
     * Unique quotation number generated by system.
     *
     * Example:
     * QUO-CDSO-BALAJI-001
     */
    @Column(nullable = false, unique = true, length = 100)
    private String quotationNumber;

    /**
     * RFQ against which this quotation is submitted.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "rfq_id", nullable = false)
    private RFQ rfq;

    /**
     * Vendor-wise RFQ mapping.
     *
     * This connects quotation with the specific vendor invited in RFQ.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "rfq_vendor_id", nullable = false)
    private RFQVendor rfqVendor;

    /**
     * Vendor who submitted this quotation.
     *
     * Example:
     * Balaji Traders.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "vendor_id", nullable = false)
    private Vendor vendor;

    /**
     * Quotation date given by vendor.
     */
    @Temporal(TemporalType.DATE)
    private Date quotationDate;

    /**
     * Quotation validity date.
     *
     * Example:
     * This quotation is valid till 30-June-2026.
     */
    @Temporal(TemporalType.DATE)
    private Date validTill;

    /**
     * Quotation version number.
     *
     * Example:
     * Vendor first submitted V1.
     * Later revised quotation becomes V2.
     */
    @Column(name = "version_no", nullable = false)
    private Integer versionNo = 1;

    /**
     * Latest quotation flag.
     *
     * true = latest quotation version
     * false = old/revised version
     */
    private boolean isLatest = true;

    /**
     * Currency of quotation.
     *
     * Example:
     * INR
     */
    @Column(length = 10)
    private String currency = "INR";

    /**
     * Basic amount before tax.
     */
    @Column(precision = 15, scale = 2)
    private BigDecimal subtotalAmount = BigDecimal.ZERO;

    /**
     * Tax amount like GST.
     */
    @Column(precision = 15, scale = 2)
    private BigDecimal taxAmount = BigDecimal.ZERO;

    /**
     * Final quotation amount including tax.
     */
    @Column(precision = 15, scale = 2)
    private BigDecimal grandTotal = BigDecimal.ZERO;

    /**
     * Delivery time in days.
     *
     * Example:
     * 5 days, 10 days, 15 days.
     */
    private Integer deliveryDays;

    /**
     * Vendor payment terms.
     *
     * Example:
     * 50% advance, 50% after delivery.
     */
    @Column(length = 1000)
    private String paymentTerms;

    /**
     * Warranty or service terms, if applicable.
     */
    @Column(length = 1000)
    private String warrantyTerms;

    /**
     * Additional vendor remarks.
     */
    @Column(length = 1000)
    private String remarks;

    /**
     * Uploaded quotation file URL.
     *
     * Example:
     * PDF quotation sent by vendor.
     */
    @Column(length = 500)
    private String quotationAttachmentUrl;

    /**
     * Status of this quotation.
     */
    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 50)
    private VendorQuotationStatus status = VendorQuotationStatus.SUBMITTED;

    /**
     * User ID who entered quotation in system.
     */
    private Long createdBy;

    /**
     * User ID who last updated quotation.
     */
    private Long updatedBy;

    @Temporal(TemporalType.TIMESTAMP)
    private Date createdDate;

    @Temporal(TemporalType.TIMESTAMP)
    private Date updatedDate;

    private boolean isDeleted = false;

    /**
     * Quotation item details.
     *
     * Example:
     * Cement, Steel Bars, Transport Charges, etc.
     */
    @OneToMany(mappedBy = "quotation", cascade = CascadeType.ALL, orphanRemoval = true)
    private List<VendorQuotationItem> items = new ArrayList<>();

    @PrePersist
    public void onCreate() {
        this.createdDate = new Date();
        this.updatedDate = new Date();
    }

    @PreUpdate
    public void onUpdate() {
        this.updatedDate = new Date();
    }
}